SELECT u.name, o.id
FROM users u INNER JOIN orders o ON u.id = o.user_id;

-- FULL OUTER JOIN
SELECT u.name, o.id
FROM users u FULL OUTER JOIN orders o ON u.id = o.user_id;

SELECT *
FROM users
WHERE phone IS NULL;

WITH recent_orders AS (
  SELECT * FROM orders
)
SELECT * FROM recent_orders;

